func failuresResultClass(level string) string {
	switch level {
	case "warning":
		return "bg-warning/10 border-warning/30"
	case "error":
		return "bg-error/10 border-error/30"
	default:
		return "bg-info/10 border-info/30"
	}
}

func failuresResultBadge(level string) string {
	switch level {
	case "warning":
		return "badge-warning"
	case "error":
		return "badge-error"
	default:
		return "badge-info"
	}
}

